sql:
SELECT d.developer_name
FROM developers d
JOIN pull_requests pr ON d.developer_name = pr.reviewer;

SELECT d.developer_name, d.email
FROM developers d
JOIN documentation doc ON d.developer_name = doc.author;

SELECT docs_eta
FROM documentation
ORDER BY docs_eta ASC;

SELECT DISTINCT assignee
FROM features
WHERE assignee NOT IN (
    SELECT dev_lead
    FROM features
);

external_knowledge:
; A "pull request" is a way for developers to propose changes to a project's codebase; 
; Merging a pull request means incorporating the proposed changes into the main codebase;
; A "developer" refers to a person who writes code for a project;
; A "Special Interest Group" (SIG) is a community of developers with shared interests or expertise;
; An "entity" refers to an organization or company that is involved in the project.

sql:
SELECT f.name AS feature_name, d.developer_name AS development_lead
FROM features f
INNER JOIN developers d ON f.dev_lead = d.developer_name;
